// Calcula rangos de fechas en formato ISO y Unix
const now = new Date();
const tz = 'Europe/Madrid';

function startOfDay(d){ const x=new Date(d); x.setHours(0,0,0,0); return x; }
function addDays(d,n){ const x=new Date(d); x.setDate(x.getDate()+n); return x; }

const todayStart = startOfDay(now);
const yesterdayStart = addDays(todayStart, -1);
const tomorrowStart = addDays(todayStart, 1);

// Semana ISO (lunes a domingo)
const day = todayStart.getDay() || 7; // 1..7
const weekStart = addDays(todayStart, -(day-1));
const lastWeekStart = addDays(weekStart, -7);

// Hace 7 días (para heatmap)
const sevenDaysAgo = addDays(todayStart, -6);

const toISO = d => d.toISOString();
const toUnix = d => Math.floor(d.getTime()/1000);

return [{ json: {
  today_start: toISO(todayStart),
  today_start_unix: toUnix(todayStart),
  yesterday_start: toISO(yesterdayStart),
  yesterday_start_unix: toUnix(yesterdayStart),
  tomorrow_start: toISO(tomorrowStart),
  tomorrow_start_unix: toUnix(tomorrowStart),
  week_start: toISO(weekStart),
  week_start_unix: toUnix(weekStart),
  last_week_start: toISO(lastWeekStart),
  last_week_start_unix: toUnix(lastWeekStart),
  seven_days_ago: toISO(sevenDaysAgo),
  seven_days_ago_unix: toUnix(sevenDaysAgo),
  now_iso: toISO(now)
} }];

// Consolida todos los resultados en un único JSON para el dashboard
// Los nodos previos están conectados al merge; recuperamos sus salidas por nombre.

function getCount(name) {
  try { const d = $items(name, 0, 0)[0].json; return d.count ?? (d.results ? d.results.length : 0); }
  catch(e){ return null; }
}
function getResults(name) {
  try { return $items(name, 0, 0)[0].json.results || []; } catch(e){ return []; }
}

const today      = getCount('Zendesk · Tickets hoy');
const yesterday  = getCount('Zendesk · Tickets ayer');
const week       = getCount('Zendesk · Tickets semana');
const lastWeek   = getCount('Zendesk · Tickets semana anterior');
const open       = getCount('Zendesk · Tickets abiertos');
const integration= getCount('Zendesk · Tickets integración');

const openResults = getResults('Zendesk · Tickets abiertos');
const integrationResults = getResults('Zendesk · Tickets integración');
const heatmapResults = getResults('Zendesk · Tickets 7 días (heatmap)');
const topTicketResults = getResults('Zendesk · Top ticket');

// Pendientes (status=pending)
const pending = openResults.filter(t => t.status === 'pending').length;
const integrationOpen = integrationResults.filter(t => t.status && t.status !== 'solved' && t.status !== 'closed').length;

// Heatmap 7 días x 24 horas
const dayLabels = ['Lun','Mar','Mié','Jue','Vie','Sáb','Dom'];
const hours = Array.from({length:24}, (_,i) => String(i).padStart(2,'0'));
const matrix = {}; // matrix[diaNombre][hh] = count

for (const d of dayLabels) {
  matrix[d] = {};
  for (const h of hours) matrix[d][h] = 0;
}
for (const t of heatmapResults) {
  if (!t.created_at) continue;
  const dt = new Date(t.created_at);
  const jsDay = dt.getDay();        // 0=Dom..6=Sáb
  const dIdx  = (jsDay + 6) % 7;     // 0=Lun..6=Dom
  const dName = dayLabels[dIdx];
  const hh    = String(dt.getHours()).padStart(2,'0');
  matrix[dName][hh]++;
}
const heatmap = dayLabels.map(d => ({
  name: d,
  data: hours.map(h => ({ x: h, y: matrix[d][h] }))
}));

// Top organizaciones (a partir de tickets abiertos; ideal: ampliar a últimos 30 días)
const orgCount = new Map();
for (const t of openResults) {
  const orgId = t.organization_id;
  if (!orgId) continue;
  orgCount.set(orgId, (orgCount.get(orgId) || 0) + 1);
}
// NOTA: para nombres reales habría que resolver org_id -> nombre vía API.
// Aquí dejamos el id como placeholder. (Ver nodo 'Resolver orgs' opcional.)
const top_orgs = [...orgCount.entries()]
  .sort((a,b)=>b[1]-a[1])
  .slice(0,8)
  .map(([id,count]) => ({ name: `Organización ${id}`, count }));

// Top ticket
let top_ticket = null;
if (topTicketResults.length > 0) {
  const t = topTicketResults[0];
  top_ticket = {
    id: t.id,
    subject: t.subject || t.raw_subject || '—',
    status: t.status,
    priority: t.priority,
    requester: t.via?.source?.from?.name || null,
    organization: t.organization_id ? `Organización ${t.organization_id}` : null,
    comments: t.comment_count || null,
    updated_at: t.updated_at ? new Date(t.updated_at).toLocaleString('es-ES') : null
  };
}

// Asana (placeholder; sustituir por nodos reales)
const asana_open = 0;
const asana_overdue = 0;

return [{ json: {
  generated_at: new Date().toISOString(),
  tickets_today: today,
  tickets_yesterday: yesterday,
  tickets_week: week,
  tickets_last_week: lastWeek,
  tickets_open: open,
  tickets_pending: pending,
  tickets_integration: integration,
  tickets_integration_open: integrationOpen,
  heatmap,
  top_orgs,
  top_ticket,
  asana_open,
  asana_overdue
} }];
